package com.example.nofiltercoffee; import android.content.*; import android.os.*; import android.widget.*; import androidx.appcompat.app.*;
public class OrderSuccessActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_order_success);String id=getIntent().getStringExtra("orderId"),time=getIntent().getStringExtra("pickupTime");((TextView)findViewById(R.id.txtOrderId)).setText("Order ID: "+id);((TextView)findViewById(R.id.txtPickupTime)).setText("Estimated pickup time: "+time);findViewById(R.id.btnBackHome).setOnClickListener(v->{startActivity(new Intent(this,HomeActivity.class).setFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP|Intent.FLAG_ACTIVITY_NEW_TASK));finish();});}}
